using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalised greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name,
        [Description("Optional language code (en, es, fr). Defaults to en.")] string language = "en")
    {
        return language.ToLowerInvariant() switch
        {
            "es" => $"¡Hola, {name}!",
            "fr" => $"Bonjour, {name} !",
            _ => $"Hello, {name}!"
        };
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of available API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

